# -*- coding: utf-8 -*-
import json

NEW_INTRO = {
"1": "Основные понятия: Механическое движение — это изменение положения тела в пространстве относительно других тел (тела отсчёта) с течением времени; движение всегда относительно — оно определяется только по отношению к выбранной системе отсчёта, вне которой понятие «движется» или «покоится» не имеет смысла. Чтобы полностью описать движение, нужно знать, где тело находится в каждый момент времени (это и есть кинематика — раздел механики, отвечающий на вопрос «как» движется тело, но не «почему»). Для этого вводят набор взаимосвязанных величин: траекторию, путь, перемещение, скорость и ускорение — каждая раскрывает свою сторону движения.",
"2": "Основные понятия: Радиус-вектор — способ однозначно «адресовать» тело в пространстве: это вектор, идущий из выбранного начала координат прямо к телу, и его конец в каждый момент времени совпадает с положением тела. Меняя момент времени, мы получаем меняющийся радиус-вектор — вся кинематика движения тела фактически сводится к тому, как r(t) изменяется во времени. Это базовая, «нулевая» величина, из которой затем определяются перемещение, скорость и ускорение через операции вычитания и дифференцирования.",
"3": "Основные понятия: Перемещение — вектор, который «напрямую» соединяет начальную и конечную точки движения, то есть кратчайший путь от старта к финишу, не важно, каким извилистым был реальный маршрут. Именно поэтому перемещение может быть меньше пройденного пути или даже равно нулю (если тело вернулось в исходную точку), хотя путь при этом положителен. Различие между перемещением и путём — ключевое для понимания разницы между векторными и скалярными характеристиками движения.",
"4": "Основные понятия: Пройденный путь — скалярная величина, равная длине реальной траектории, по которой двигалось тело, то есть «сколько метров накрутил спидометр», без учёта направления. В отличие от перемещения путь никогда не убывает и не может быть отрицательным: он суммируется вдоль всей траектории независимо от того, возвращалось тело назад или нет. При прямолинейном движении в одном направлении путь и модуль перемещения совпадают, но при любом развороте или криволинейном движении путь оказывается больше.",
"5": "Основные понятия: Траектория — это воображаемая линия в пространстве, которую «вычерчивает» тело при своём движении; она может быть прямой (прямолинейное движение) или изогнутой любой формы (криволинейное движение, в частности окружность при вращении). Траектория относительна: одно и то же движение в разных системах отсчёта выглядит по-разному — например, точка на ободе катящегося колеса описывает сложную кривую (циклоиду) относительно земли, но простую окружность относительно оси колеса. Форма траектории определяет, какими будут скорость и ускорение тела в каждой точке пути.",
"6": "Основные понятия: Мгновенная скорость — это скорость тела в конкретный, бесконечно малый момент времени, то есть предел, к которому стремится средняя скорость при стягивании промежутка времени к нулю; именно её показывает спидометр автомобиля в любой момент. Мгновенная скорость — вектор, направленный по касательной к траектории в данной точке, поэтому она отвечает не только на вопрос «как быстро», но и «в какую сторону в данный момент» движется тело. Математически это производная радиус-вектора по времени — величина, характеризующая скорость изменения положения.",
"7": "Основные понятия: Средняя скорость — это «усреднённая» характеристика движения за конечный промежуток времени, которая не показывает, как менялась скорость внутри этого промежутка, а лишь суммарный результат: какое перемещение (или путь) тело совершило за данное время. Различают среднюю скорость перемещения (векторную величину, определяемую отношением перемещения ко времени) и среднюю путевую скорость (скалярную, отношение пути ко времени) — эти величины совпадают только при движении без изменения направления. Средняя скорость особенно полезна, когда реальное движение неравномерно и отследить мгновенную скорость в каждой точке невозможно или не нужно.",
"8": "Основные понятия: Ускорение показывает, насколько быстро меняется скорость тела — как по величине (тело разгоняется или тормозит), так и по направлению (тело поворачивает). Именно поэтому даже равномерное движение по окружности является ускоренным: скорость постоянна по модулю, но постоянно меняет направление, порождая центростремительное ускорение. Полное ускорение можно разложить на тангенциальную составляющую (отвечает за изменение модуля скорости) и нормальную (отвечает за изменение направления) — это разложение лежит в основе анализа любого криволинейного движения.",
"9": "Основные понятия: Сила тяжести — это сила гравитационного притяжения тела к Земле, действующая на любое тело независимо от того, движется оно или покоится, соприкасается с опорой или свободно падает. Она всегда направлена вертикально вниз, к центру Земли, и в первом приближении не зависит от свойств самого тела (кроме его массы), поэтому все тела в вакууме падают с одинаковым ускорением свободного падения. Силу тяжести важно не путать с весом тела — весом называют силу давления тела на опору или подвес, которая совпадает с силой тяжести только при отсутствии ускорения у опоры.",
"10": "Основные понятия: Сила упругости возникает при деформации тела (растяжении, сжатии, изгибе) и всегда направлена так, чтобы вернуть тело к недеформированному состоянию — это сила «сопротивления» изменению формы. В основе лежит закон Гука: в пределах упругости сила пропорциональна величине деформации, а коэффициент пропорциональности (жёсткость) характеризует, насколько «жёстким» или «мягким» является тело. Понимание упругих сил важно не только для пружин и стержней, но и для биологических тканей — сосудов, связок, мышц, — упругие свойства которых определяют их механическое поведение в организме.",
"11": "Основные понятия: Сила сопротивления (трения, сопротивления среды) — это сила, препятствующая относительному движению соприкасающихся тел или движению тела в жидкости/газе, направленная всегда против скорости движения. В твёрдых телах различают трение покоя (не даёт телу сдвинуться) и трение скольжения (тормозит уже движущееся тело); в жидкостях и газах сопротивление растёт с ростом скорости — при малых скоростях линейно (вязкое сопротивление), при больших — квадратично (сопротивление за счёт образования вихрей). Именно силы сопротивления объясняют, почему без постоянного приложения силы движение в реальном мире всегда замедляется и останавливается.",
"12": "Основные понятия: Первый закон Ньютона (закон инерции) утверждает, что тело сохраняет состояние покоя или равномерного прямолинейного движения, пока внешние силы не выведут его из этого состояния — то есть само по себе тело «не хочет» менять своё движение. Этот закон фактически определяет, что такое инерциальная система отсчёта: это система, в которой закон инерции выполняется. Физический смысл закона в том, что для изменения скорости тела (то есть для ускорения) обязательно нужна причина — сила; отсутствие силы означает отсутствие ускорения, а не отсутствие движения.",
"13": "Основные понятия: Второй закон Ньютона — центральный закон динамики: он связывает причину (силу) со следствием (ускорением) и показывает, что ускорение тела прямо пропорционально приложенной силе и обратно пропорционально массе тела. Масса здесь выступает как мера инертности — чем она больше, тем труднее изменить скорость тела данной силой. Закон работает для равнодействующей всех сил, приложенных к телу, и позволяет предсказать движение тела, если известны все действующие на него силы — это основа всей классической механики.",
"14": "Основные понятия: Третий закон Ньютона описывает взаимодействие, а не движение одного тела: если тело А действует на тело Б с некоторой силой, то тело Б обязательно действует на тело А с силой такой же величины, но противоположного направления. Важно, что эти две силы приложены к разным телам и поэтому не уравновешивают друг друга (не складываются в ноль для системы «А+Б в целом»), а вызывают ускорение каждого тела согласно второму закону. Именно третий закон объясняет, как возможно оттолкнуться ногами от земли при ходьбе, или как работает реактивное движение — отбрасывание массы в одну сторону создаёт силу тяги в другую.",
"15": "Основные понятия: Закон всемирного тяготения описывает универсальную силу притяжения, действующую между любыми двумя телами, обладающими массой, — от молекул до планет и звёзд. Сила пропорциональна произведению масс тел и убывает обратно пропорционально квадрату расстояния между ними, поэтому гравитация является дальнодействующей, но быстро слабеющей с расстоянием силой. Этот закон объясняет как падение яблока на землю, так и удержание планет на орбитах — это одна и та же физическая природа, что было революционным открытием Ньютона, объединившим «земную» и «небесную» механику.",
"16": "Основные понятия: Механическая работа — это мера действия силы, приводящего к перемещению тела: работа совершается только тогда, когда сила имеет составляющую вдоль направления перемещения, а сила, действующая перпендикулярно движению (например, центростремительная), работы не совершает. Работа может быть положительной (сила «помогает» движению, разгоняя тело) или отрицательной (сила тормозит тело, отбирая у него энергию) — знак работы показывает, к телу энергия притекает или утекает. Именно через работу вводится понятие энергии: работа силы равна изменению энергии тела, над которым она совершается.",
"17": "Основные понятия: Импульс тела (количество движения) — векторная величина, характеризующая совокупное «количество» движения тела с учётом и массы, и скорости: чем массивнее и быстрее тело, тем труднее его остановить или изменить его движение. Импульс направлен так же, как скорость, и является одной из фундаментальных сохраняющихся величин физики — в замкнутой системе суммарный импульс не меняется, даже если тела внутри системы сталкиваются, взаимодействуют и обмениваются энергией. Понятие импульса особенно удобно при анализе столкновений и взрывов, где силы взаимодействия велики, но кратковременны, и напрямую применить второй закон Ньютона сложно.",
"18": "Основные понятия: Импульс силы — это мера действия силы во времени, показывающая, насколько сильно и как долго сила «толкала» тело; именно импульс силы, а не сама сила, определяет итоговое изменение импульса тела. Это объясняет, почему одинаковое изменение скорости можно получить как кратковременным сильным ударом, так и длительным слабым воздействием — важен именно интеграл силы по времени. Практическое следствие: чтобы уменьшить вред от удара (например, при падении или столкновении), нужно увеличить время воздействия силы — тогда сама сила при той же импульсе силы будет меньше (принцип действия амортизаторов, подушек безопасности, техники приземления).",
"19": "Основные понятия: Кинетическая энергия — это энергия движущегося тела, мера способности тела совершить работу за счёт своего движения (например, затормозить и передать эту энергию другому телу при столкновении). Она растёт пропорционально квадрату скорости, поэтому при увеличении скорости в два раза кинетическая энергия увеличивается в четыре раза — этим объясняется резкое возрастание тяжести последствий ДТП или травм при росте скорости. Кинетическая энергия — скалярная и всегда неотрицательная величина, она характеризует движение независимо от его направления.",
"20": "Основные понятия: Потенциальная энергия — это энергия, которой тело обладает благодаря своему положению в потенциальном силовом поле (гравитационном, упругом и др.), то есть «запасённая» способность совершить работу за счёт изменения этого положения. Она существует только для консервативных сил (таких, работа которых не зависит от формы траектории, а только от начальной и конечной точки) — например, для силы тяжести или силы упругости, но не для силы трения. Потенциальная энергия определена с точностью до выбора нулевого уровня отсчёта, но физический смысл имеет именно её изменение, которое равно работе, совершённой против соответствующей силы.",
"21": "Основные понятия: Закон сохранения импульса — один из фундаментальных законов природы: в замкнутой системе (на которую не действуют внешние силы или их равнодействующая равна нулю) суммарный векторный импульс всех тел остаётся постоянным, как бы тела ни взаимодействовали между собой. Внутренние силы взаимодействия (по третьему закону Ньютона) всегда компенсируют друг друга при суммировании по всей системе, поэтому они не могут изменить общий импульс — импульс может только «перераспределяться» между телами системы. Этот закон особенно удобен для анализа столкновений, взрывов, реактивного движения — ситуаций, где детально проследить действующие силы сложно или невозможно.",
"22": "Основные понятия: Закон сохранения энергии — фундаментальный закон природы: полная энергия замкнутой системы (сумма всех её видов — кинетической, потенциальной, внутренней и т.д.) остаётся постоянной, энергия не создаётся и не исчезает, а лишь переходит из одной формы в другую. В механике для консервативных систем (без трения и других диссипативных сил) отдельно сохраняется сумма кинетической и потенциальной энергии; при наличии трения часть механической энергии необратимо переходит в тепло, но полная энергия системы (с учётом тепла) по-прежнему сохраняется. Этот закон — один из самых универсальных в физике, он справедлив не только в механике, но и в термодинамике, электродинамике и биологии живых систем.",
"23": "Основные понятия: Колебания — это повторяющееся во времени движение (или изменение какой-либо величины) вокруг положения равновесия, при котором система периодически возвращается к исходному состоянию. Для полного описания колебаний используют набор параметров: амплитуду (максимальное отклонение от равновесия), период (время одного полного цикла), частоту (число циклов в единицу времени) и фазу (характеризует состояние колебательной системы в конкретный момент времени). Колебания универсальны — они встречаются в механике (маятники, вибрации), в электрических цепях, в биологических системах (сердечный ритм, дыхание, биоэлектрические процессы).",
"24": "Основные понятия: Уравнение гармонических колебаний описывает простейший, но фундаментально важный тип колебаний, при котором смещение изменяется во времени по синусоидальному (или косинусоидальному) закону — такие колебания возникают, когда возвращающая сила прямо пропорциональна отклонению от положения равновесия (как в законе Гука). Гармонические колебания важны потому, что любое сложное периодическое колебание, согласно теореме Фурье, можно представить как сумму (набор) простых гармонических колебаний разных частот и амплитуд. Это делает гармонический осциллятор базовой моделью для описания огромного числа физических и биологических периодических процессов.",
"25": "Основные понятия: При гармонических колебаниях кинетическая и потенциальная энергия непрерывно переходят друг в друга: в момент максимального отклонения от равновесия скорость тела равна нулю, вся энергия потенциальная; при прохождении положения равновесия отклонение равно нулю, но скорость максимальна — вся энергия кинетическая. Сумма кинетической и потенциальной энергии в идеальном (без потерь) колебательном процессе остаётся постоянной в любой момент времени — это частный случай закона сохранения энергии применительно к колебаниям. Именно этот непрерывный обмен энергией между двумя формами и поддерживает сами колебания.",
"26": "Основные понятия: Затухающие колебания возникают, когда на колебательную систему помимо возвращающей силы действует сила сопротивления (трения), которая постепенно отбирает энергию у системы, — из-за этого амплитуда колебаний со временем уменьшается, стремясь к нулю. Скорость затухания характеризуется коэффициентом затухания: чем он больше, тем быстрее гаснут колебания, вплоть до апериодического режима, когда система вообще не совершает колебаний, а просто монотонно возвращается к равновесию. Затухающие колебания — более реалистичная модель, чем идеальные гармонические, поскольку в реальном мире силы сопротивления присутствуют практически всегда.",
"27": "Основные понятия: Уравнение затухающих колебаний математически описывает одновременно два процесса: собственно колебательное движение (синусоидальную составляющую) и экспоненциальное уменьшение амплитуды со временем из-за потерь энергии на трение. Произведение этих двух множителей даёт характерную картину «затухающей волны» — колебания с постепенно уменьшающейся амплитудой, огибающая которых представляет собой экспоненту. Это уравнение позволяет количественно предсказать, как быстро и по какому закону затухнут реальные колебания в конкретной системе.",
"28": "Основные понятия: Вынужденные колебания возникают, когда на колебательную систему действует внешняя периодическая сила, компенсирующая потери энергии на трение и поддерживающая колебания незатухающими; частота таких колебаний определяется частотой внешней вынуждающей силы, а не собственными свойствами системы. Резонанс — это резкое возрастание амплитуды вынужденных колебаний, которое происходит, когда частота вынуждающей силы приближается к собственной частоте колебательной системы: в этом случае внешняя сила максимально эффективно «раскачивает» систему. Резонансные явления важны и опасны одновременно — они лежат в основе работы многих приборов, но также могут приводить к разрушению конструкций или резонансным повреждениям в биологических тканях (например, при воздействии вибрации или ультразвука).",
"29": "Основные понятия: Уравнение вынужденных колебаний описывает установившийся режим, при котором система колеблется с частотой внешней вынуждающей силы, а амплитуда этих колебаний зависит от соотношения частоты вынуждающей силы и собственной частоты системы, а также от степени затухания (трения) в системе. При приближении частоты вынуждающей силы к собственной частоте амплитуда резко растёт (явление резонанса), а трение ограничивает этот рост, не позволяя амплитуде стать бесконечной. Это уравнение — математическая основа для расчёта резонансных характеристик любых колебательных систем, от мостов и зданий до электрических контуров.",
"30": "Основные понятия: Механическая волна — это процесс распространения колебаний в упругой среде, при котором частицы среды не переносятся вместе с волной, а лишь колеблются около своих положений равновесия, передавая энергию и импульс соседним частицам через силы упругости. Основные характеристики волны — длина волны (расстояние между соседними точками, колеблющимися в одинаковой фазе), период и частота колебаний, скорость распространения волны в данной среде. Волны бывают продольными (частицы колеблются вдоль направления распространения волны, как звук в воздухе) и поперечными (частицы колеблются перпендикулярно направлению распространения, как волны на поверхности воды или в твёрдом теле).",
"31": "Основные понятия: Уравнение гармонической волны описывает смещение любой частицы среды как функцию и координаты, и времени одновременно — оно показывает, что колебание, начавшееся в одной точке среды, повторяется в других точках, но со сдвигом по времени (фазе), пропорциональным расстоянию до источника и обратно пропорциональным скорости волны. Это уравнение позволяет для любой точки пространства в любой момент времени рассчитать, в какой фазе колебания она находится и каково её смещение от положения равновесия. Волновое уравнение — фундаментальный математический инструмент, применимый не только к механическим, но и к электромагнитным волнам.",
"32": "Основные понятия: Интенсивность волны — это энергетическая характеристика волны, показывающая, какое количество энергии переносится волной через единичную площадку, перпендикулярную направлению распространения, за единицу времени. Интенсивность пропорциональна квадрату амплитуды колебаний и квадрату частоты, поэтому даже небольшое увеличение амплитуды сильно увеличивает переносимую волной энергию. По мере удаления от точечного источника интенсивность убывает обратно пропорционально квадрату расстояния (энергия «размазывается» по всё большей сферической поверхности) — это важно для понимания того, почему звук или свет ослабевают с расстоянием.",
"33": "Основные понятия: Звук — это механическая волна, распространяющаяся в упругой среде (воздухе, жидкости, твёрдом теле) в диапазоне частот, воспринимаемых человеческим ухом как слуховое ощущение (примерно от 16 Гц до 20 кГц). По своей физической природе звук — продольная волна (в газах и жидкостях), то есть чередование областей сжатия и разрежения среды, распространяющихся от источника колебаний. Звук не может распространяться в вакууме, поскольку для его переноса необходима упругая среда, частицы которой могут передавать колебания друг другу.",
"34": "Основные понятия: Объективные характеристики звука — это физические величины, которые можно измерить приборами независимо от восприятия человека: частота колебаний, интенсивность (энергетическая мощность волны) и спектральный состав (набор частот, из которых состоит звук). Субъективные характеристики — это то, как звук воспринимается человеческим слухом: высота тона (субъективный аналог частоты), громкость (субъективный аналог интенсивности) и тембр (субъективный аналог спектрального состава, позволяющий отличать разные источники звука одной высоты и громкости). Связь между объективными и субъективными характеристиками не линейна — например, громкость связана с интенсивностью логарифмической зависимостью (закон Вебера-Фехнера), что отражает особенности работы органов чувств.",
"35": "Основные понятия: Звуковые методы в медицине используют механические колебания слышимого и неслышимого (ультразвукового) диапазона для диагностики и лечения. К ним относятся, в частности, аускультация (выслушивание звуков, возникающих внутри организма — тонов сердца, дыхательных шумов) и перкуссия (анализ звука, возникающего при простукивании тканей, для оценки их плотности и наличия полостей). Такие методы информативны потому, что физические свойства тканей (плотность, упругость, наличие газа или жидкости) напрямую определяют, как в них распространяется и отражается звук — по характеру звука можно судить о состоянии органа.",
"36": "Основные понятия: Ультразвук — это механические волны той же природы, что и звук, но с частотой выше порога слышимости человеческого уха — обычно от 20 кГц и выше. Из-за высокой частоты ультразвук имеет малую длину волны, что позволяет ему хорошо фокусироваться в узкий пучок и давать высокое пространственное разрешение при формировании изображений — на этом основана ультразвуковая диагностика (УЗИ). Ультразвук способен отражаться на границах сред с разной акустической плотностью, что и используется для визуализации внутренних структур организма без ионизирующего облучения.",
"37": "Основные понятия: Основные свойства ультразвука определяются его волновой природой и высокой частотой: он хорошо отражается на границах сред с разным акустическим сопротивлением (что используется для эхолокации и УЗИ-диагностики), может фокусироваться в узкий направленный пучок (в отличие от звука низких частот, который сильно рассеивается), способен проникать в ткани на значительную глубину при относительно малом рассеянии. При достаточно большой интенсивности ультразвук может оказывать механическое, тепловое и кавитационное воздействие на ткани — это используется как в диагностике (малые интенсивности), так и в физиотерапии и хирургии (большие интенсивности).",
"38": "Основные понятия: Идеальная жидкость — это физическая модель, упрощающая реальную жидкость: она считается несжимаемой (плотность не меняется под действием давления) и невязкой (отсутствует внутреннее трение между слоями жидкости при их относительном движении). Эта модель позволяет применять сравнительно простой математический аппарат (уравнение Бернулли, уравнение неразрывности) для расчёта течений, когда вязкостью и сжимаемостью реальной жидкости можно пренебречь. Реальные жидкости (кровь, вода) в ряде случаев с хорошей точностью приближаются к идеальным, но для более точного описания (особенно течения крови в мелких сосудах) вязкость учитывать необходимо.",
"39": "Основные понятия: Линейная скорость течения жидкости показывает, с какой скоростью движутся частицы жидкости в данном сечении потока (м/с), тогда как объёмная скорость (расход) показывает, какой объём жидкости протекает через сечение за единицу времени (м³/с). Эти величины связаны между собой через площадь поперечного сечения потока: при одном и том же расходе жидкости в узких участках линейная скорость должна быть выше, а в широких — ниже. Это соотношение объясняет, например, почему кровь движется быстрее в аорте, чем суммарно в капиллярах, несмотря на то, что общий объёмный расход крови через любое сечение сосудистой системы одинаков.",
"40": "Основные понятия: Уравнение неразрывности струи выражает закон сохранения массы (объёма) жидкости при её течении по трубе переменного сечения: если жидкость несжимаема и не накапливается и не исчезает внутри трубы, то через любое сечение потока за одинаковое время должен протекать одинаковый объём жидкости. Отсюда следует, что произведение площади сечения на линейную скорость потока постоянно вдоль трубы — там, где сечение уже, скорость должна быть больше, и наоборот. Этот закон — фундамент гидродинамики и напрямую применим к анализу кровотока в сосудах разного диаметра.",
"41": "Основные понятия: Уравнение Бернулли выражает закон сохранения энергии для течения идеальной жидкости: сумма давления, кинетической энергии единицы объёма жидкости (связанной со скоростью течения) и потенциальной энергии (связанной с высотой) остаётся постоянной вдоль линии тока. Из этого следует ключевое практическое следствие: там, где скорость потока жидкости выше, давление в ней ниже, и наоборот — это объясняет множество явлений, от подъёмной силы крыла самолёта до особенностей кровотока в местах сужения сосудов. Уравнение Бернулли — одно из важнейших уравнений гидродинамики, применимое (с поправками на вязкость) и к течению крови в организме.",
"42": "Основные понятия: Вязкость — это внутреннее трение между соседними слоями жидкости, движущимися с разной скоростью относительно друг друга; она возникает из-за молекулярного взаимодействия частиц жидкости и препятствует их свободному «проскальзыванию» друг относительно друга. Именно вязкость определяет, что для поддержания течения реальной (не идеальной) жидкости по трубе нужно постоянно затрачивать энергию — на преодоление этого внутреннего трения расходуется энергия, которая переходит в тепло. Вязкость крови — важнейший физиологический параметр, от которого напрямую зависит сопротивление кровотоку и, соответственно, работа сердца по его поддержанию.",
"43": "Основные понятия: Формула Ньютона описывает силу внутреннего трения между слоями вязкой жидкости: эта сила пропорциональна площади соприкасающихся слоёв и градиенту скорости (тому, насколько быстро меняется скорость жидкости при переходе от слоя к слою), а коэффициентом пропорциональности выступает вязкость жидкости. Чем больше разница скоростей соседних слоёв на единицу расстояния между ними, тем сильнее они «тормозят» друг друга силами вязкого трения. Эта формула — основа для расчёта энергетических потерь при течении жидкости по трубам, в том числе для оценки гидравлического сопротивления сосудов.",
"44": "Основные понятия: Закон Пуазейля описывает течение вязкой жидкости по узкой цилиндрической трубе (например, кровеносному сосуду) и связывает объёмный расход жидкости с разностью давлений на концах трубы, радиусом трубы, длиной трубы и вязкостью жидкости. Ключевая особенность закона в том, что расход чрезвычайно сильно (в четвёртой степени) зависит от радиуса трубы — при уменьшении радиуса сосуда всего вдвое сопротивление кровотоку возрастает в шестнадцать раз. Именно поэтому даже небольшое сужение сосуда (например, атеросклеротической бляшкой или спазмом) резко увеличивает нагрузку на сердце, необходимую для поддержания нужного кровотока.",
"45": "Основные понятия: Ньютоновские жидкости — это жидкости, вязкость которых является постоянной величиной, не зависящей от скорости течения или приложенных напряжений (например, вода, плазма крови); для них справедлива простая формула Ньютона для силы вязкого трения. Неньютоновские жидкости — это жидкости, вязкость которых меняется в зависимости от режима течения (скорости сдвига), например, растёт при уменьшении скорости течения; классический пример — цельная кровь, вязкость которой увеличивается при малых скоростях кровотока из-за агрегации эритроцитов. Различие между ньютоновскими и неньютоновскими жидкостями важно для понимания того, почему поведение крови в мелких сосудах (капиллярах) значительно сложнее, чем в крупных артериях.",
"46": "Основные понятия: Ламинарное движение жидкости — это упорядоченное, слоистое течение, при котором частицы жидкости движутся параллельными траекториями, не перемешиваясь между слоями; такое течение спокойное, бесшумное и энергетически более выгодное. Турбулентное движение — это хаотичное течение с образованием вихрей, при котором частицы жидкости перемешиваются между слоями в разных направлениях; оно требует значительно большей энергии для поддержания того же расхода жидкости и часто сопровождается шумом (это используется, например, при аускультации патологических шумов в сосудах и сердце). Переход от ламинарного течения к турбулентному происходит при превышении определённой критической скорости, зависящей от свойств жидкости и трубы.",
"47": "Основные понятия: Число Рейнольдса — это безразмерная величина, которая позволяет предсказать, каким будет режим течения жидкости — ламинарным или турбулентным, — без необходимости проводить эксперимент заново для каждой конкретной жидкости и трубы. Оно представляет собой отношение сил инерции (стремящихся сделать течение хаотичным) к силам вязкости (стремящихся сохранить упорядоченное течение): при малых значениях числа Рейнольдса вязкость «побеждает» и течение остаётся ламинарным, при превышении критического значения инерционные эффекты берут верх и возникает турбулентность. В медицине число Рейнольдса помогает объяснить, почему в норме кровоток в большинстве сосудов ламинарный, но может становиться турбулентным в местах сужений, разветвлений или при патологически повышенной скорости кровотока.",
"48": "Основные понятия: Система кровообращения — это замкнутая гидродинамическая система, обеспечивающая непрерывную циркуляцию крови по организму под действием насосной функции сердца; она состоит из большого круга кровообращения (доставка крови ко всем тканям тела и обратно) и малого (лёгочного) круга (насыщение крови кислородом в лёгких). С точки зрения физики, кровеносная система представляет собой сеть эластичных трубок разного диаметра (артерии, артериолы, капилляры, венулы, вены), в которой течёт вязкая неньютоновская жидкость (кровь) под действием переменного во времени давления, создаваемого пульсирующей работой сердца. Понимание физических законов гидродинамики (уравнение неразрывности, закон Пуазейля, число Рейнольдса) необходимо для анализа того, как давление, скорость и сопротивление кровотоку меняются на разных участках сосудистого русла.",
"49": "Основные понятия: Скорость кровотока, давление крови и гемодинамическое сопротивление — три взаимосвязанные величины, описывающие движение крови по сосудам подобно закону Ома для электрической цепи: разность давлений на концах сосудистого участка играет роль «движущей силы», сопротивление сосудов — роль «препятствия», а объёмная скорость кровотока — роль «тока». Гемодинамическое сопротивление зависит главным образом от радиуса сосудов (по закону Пуазейля — в четвёртой степени), поэтому наибольший вклад в общее сопротивление кровотоку вносят мелкие сосуды (артериолы), несмотря на их малую длину. Линейная скорость кровотока при этом обратно пропорциональна суммарной площади сечения сосудов данного уровня — поэтому она максимальна в аорте и минимальна в капиллярах, что важно для эффективного газообмена в тканях.",
"50": "Основные понятия: Работа сердца складывается из двух компонентов: статического (потенциального) — работы по созданию давления, необходимого для выброса крови в сосудистое русло против сопротивления, и кинетического — работы по сообщению крови скорости движения (кинетической энергии). У здорового человека в состоянии покоя основная доля работы сердца (около 99%) приходится именно на статический компонент — создание давления, тогда как кинетический компонент, связанный с приданием крови скорости, составляет лишь малую часть. Однако при физической нагрузке или патологических состояниях, повышающих скорость кровотока, доля кинетического компонента в общей работе сердца заметно возрастает.",
"51": "Основные понятия: Функциональная классификация сосудов делит сосудистую систему не по анатомическому строению, а по выполняемой физиологической (гидродинамической) роли: амортизирующие (компрессионные) сосуды — крупные эластичные артерии, сглаживающие пульсовые колебания давления; резистивные сосуды — артериолы, создающие основное сопротивление кровотоку и регулирующие его распределение; обменные сосуды — капилляры, где происходит газообмен и обмен веществ между кровью и тканями; ёмкостные сосуды — вены, вмещающие большую часть объёма крови и выполняющие роль депо. Такая классификация помогает понять, почему разные участки сосудистого русла, несмотря на общую гидродинамическую природу, выполняют принципиально разные физиологические функции.",
}

with open("physics_questions.json", "r", encoding="utf-8") as f:
    data = json.load(f)

changed = 0
for k, new_intro in NEW_INTRO.items():
    a = data[k]["answer"]
    parts = a.split("\n\n", 1)
    rest = parts[1] if len(parts) > 1 else ""
    if rest:
        data[k]["answer"] = new_intro + "\n\n" + rest
    else:
        data[k]["answer"] = new_intro
    changed += 1

with open("physics_questions.json", "w", encoding="utf-8") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("changed:", changed)
